export function IcoAreaAnalytics() {
  const { palette } = useIlloStyle();
  // 4×4 heatmap grid
  const intensities = [
    [0.10, 0.25, 0.55, 0.80],
    [0.18, 0.40, 0.85, 0.60],
    [0.30, 0.70, 0.95, 0.45],
    [0.12, 0.35, 0.50, 0.25],
  ];
  const cellW = 34, cellH = 24, gap = 3, ox = 20, oy = 15;
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {intensities.map((row, ri) =>
        row.map((op, ci) => (
          <rect key={`${ri}-${ci}`}
            x={ox + ci * (cellW + gap)} y={oy + ri * (cellH + gap)}
            width={cellW} height={cellH} rx="4"
            fill={palette.accent} opacity={op}
          />
        ))
      )}
      {/* Grid region border */}
      <rect x={ox - 2} y={oy - 2}
        width={4 * cellW + 3 * gap + 4} height={4 * cellH + 3 * gap + 4}
        rx="6" fill="none" stroke={palette.mid} strokeWidth="1" opacity="0.25" />
      <circle cx="130" cy="95" r="6" fill={palette.accent} opacity="0.45" />
    </svg>
  );
}
